              <th className="text-left px-3 py-2 text-text-faint font-medium uppercase tracking-wide text-[9px]">Family</th>
              <th className="text-left px-3 py-2 text-text-faint font-medium uppercase tracking-wide text-[9px] hidden md:table-cell">Interest</th>
              <th className="text-left px-3 py-2 text-text-faint font-medium uppercase tracking-wide text-[9px]">Status</th>
              <th className="text-left px-3 py-2 text-text-faint font-medium uppercase tracking-wide text-[9px] hidden lg:table-cell">Tags</th>
              <th className="text-left px-3 py-2 text-text-faint font-medium uppercase tracking-wide text-[9px] hidden md:table-cell">Added</th>
            </tr>
          </thead>
          <tbody>
            {leads.map((lead, i) => (
              <tr key={i} className="border-b border-border last:border-0 hover:bg-surface-soft transition-colors">
                <td className="px-3 py-2.5 font-medium text-text">{lead.name}</td>
                <td className="px-3 py-2.5 text-text-muted hidden md:table-cell">{lead.child}</td>
                <td className="px-3 py-2.5">
                  <span className={`text-[10px] rounded-pill px-2 py-0.5 ${statusStyles[lead.status]}`}>{lead.status}</span>
                </td>
                <td className="px-3 py-2.5 hidden lg:table-cell">
                  <div className="flex gap-1 flex-wrap">
                    {lead.tags.map((tag) => (
                      <span key={tag} className="bg-accent-soft text-accent text-[9px] rounded-pill px-1.5 py-0.5">{tag}</span>
                    ))}
                  </div>
                </td>
                <td className="px-3 py-2.5 text-text-faint hidden md:table-cell">{lead.date}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}
